import { Component } from '@angular/core';

@Component({
  selector: 'app-products',
  templateUrl: './products.component.html',
  styleUrls: ['./products.component.scss']
})
export class ProductsComponent {
  products = [

    {
      id: 1,
      name: "Urban Edge",
      price: 299,
      oldPrice: 399,
      badge: "sale",
      stock: 10,
      image: "assets/images/urban-edge.avif"
    },

    {
      id: 2,
      name: "Neo Classic",
      price: 399,
      badge: "bestseller",
      stock: 5,
      image: "assets/images/neo-classic.avif"
    },

    {
      id: 3,
      name: "Minimal Chic",
      price: 89,
      badge: "new",
      stock: 3,
      image: "assets/images/minimal-chic.avif"
    },

    {
      id: 4,
      name: "Street Rebel",
      price: 199,
      badge: "trending",
      stock: 0,
      image: "assets/images/street-rebel.avif"
    },
    {
      id: 5,
      name: "Urban Edge",
      price: 299,
      oldPrice: 399,
      badge: "sale",
      stock: 10,
      image: "assets/images/urban-edge.avif"
    },

    {
      id: 6,
      name: "Neo Classic",
      price: 399,
      badge: "bestseller",
      stock: 5,
      image: "assets/images/neo-classic.avif"
    },

    {
      id: 7,
      name: "Minimal Chic",
      price: 89,
      badge: "new",
      stock: 3,
      image: "assets/images/minimal-chic.avif"
    },

    {
      id: 8,
      name: "Street Rebel",
      price: 199,
      badge: "trending",
      stock: 0,
      image: "assets/images/street-rebel.avif"
    },

    {
      id: 9,
      name: "Urban Edge",
      price: 299,
      oldPrice: 399,
      badge: "sale",
      stock: 10,
      image: "assets/images/urban-edge.avif"
    },

    {
      id: 10,
      name: "Neo Classic",
      price: 399,
      badge: "bestseller",
      stock: 5,
      image: "assets/images/neo-classic.avif"
    },

    {
      id: 11,
      name: "Minimal Chic",
      price: 89,
      badge: "new",
      stock: 3,
      image: "assets/images/minimal-chic.avif"
    },

    {
      id: 12,
      name: "Street Rebel",
      price: 199,
      badge: "trending",
      stock: 0,
      image: "assets/images/street-rebel.avif"
    },
    {
      id: 13,
      name: "Urban Edge",
      price: 299,
      oldPrice: 399,
      badge: "sale",
      stock: 10,
      image: "assets/images/urban-edge.avif"
    },

    {
      id: 14,
      name: "Neo Classic",
      price: 399,
      badge: "bestseller",
      stock: 5,
      image: "assets/images/neo-classic.avif"
    },

    {
      id: 15,
      name: "Minimal Chic",
      price: 89,
      badge: "new",
      stock: 3,
      image: "assets/images/minimal-chic.avif"
    },

    {
      id: 16,
      name: "Street Rebel",
      price: 199,
      badge: "trending",
      stock: 0,
      image: "assets/images/street-rebel.avif"
    }

  ];


  currentPage = 1;
  itemsPerPage = 3;

get totalPages() {
  return Math.ceil(this.products.length / this.itemsPerPage);
}

get paginatedProducts() {
  const start = (this.currentPage - 1) * this.itemsPerPage;
  const end = start + this.itemsPerPage;
  return this.products.slice(start, end);
}

// dynamic pagination with dots
get pages() {
  const pages: (number | string)[] = [];
  const total = this.totalPages;

  if (total <= 7) {
    for (let i = 1; i <= total; i++) pages.push(i);
  } else {
    // always show first and last
    pages.push(1);

    let start = Math.max(this.currentPage - 2, 2);
    let end = Math.min(this.currentPage + 2, total - 1);

    if (start > 2) pages.push('...');
    for (let i = start; i <= end; i++) pages.push(i);
    if (end < total - 1) pages.push('...');

    pages.push(total);
  }

  return pages;
}

goToPage(page: number | string) {
  if (typeof page === 'number') this.currentPage = page;
}

nextPage() {
  if (this.currentPage < this.totalPages) this.currentPage++;
}

prevPage() {
  if (this.currentPage > 1) this.currentPage--;
}

}
